<?php
// DB接続設定
$pdo = new PDO(
    "mysql:host=mysql3108.db.sakura.ne.jp;dbname=ma2no4413_market_info;charset=utf8mb4",
    "ma2no4413_market_info",
    "H4qH3qZMSAhyz52",
    [PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION]
);

// 最新スナップショット取得
$latest = $pdo->query("SELECT MAX(snapshot_at) FROM sector_data")->fetchColumn();

// 30日前の日付を計算
$latestDate = new DateTime($latest);
$startDate = (clone $latestDate)->modify('-30 days')->format('Y-m-d');

// 30日分のスナップショットを取得
$stmtDates = $pdo->prepare("
SELECT DISTINCT snapshot_at
FROM sector_data
WHERE snapshot_at BETWEEN :start AND :latest
ORDER BY snapshot_at ASC
");
$stmtDates->execute(['start' => $startDate, 'latest' => $latest]);
$dates = $stmtDates->fetchAll(PDO::FETCH_COLUMN);

// データがなければ最古までさかのぼる
if (count($dates) < 2) {
    $stmtDates = $pdo->query("SELECT DISTINCT snapshot_at FROM sector_data ORDER BY snapshot_at ASC");
    $dates = $stmtDates->fetchAll(PDO::FETCH_COLUMN);
}

// 最新・前回スナップショット
$prev = $pdo->query("SELECT MAX(snapshot_at) FROM sector_data WHERE snapshot_at < '$latest'")->fetchColumn();

// 最新・前回のセクターデータ取得
$stmt = $pdo->prepare("
WITH latest AS (
  SELECT sector_code, market_cap AS market_cap_latest, volume_24h AS volume_latest
  FROM sector_data WHERE snapshot_at = :latest
),
prev AS (
  SELECT sector_code, market_cap AS market_cap_prev
  FROM sector_data WHERE snapshot_at = :prev
)
SELECT sn.sector_code,
       sn.sector_name,
       l.market_cap_latest,
       p.market_cap_prev,
       (l.market_cap_latest - p.market_cap_prev) / NULLIF(p.market_cap_prev, 0) * 100 AS change_pct,
       (l.volume_latest / NULLIF(l.market_cap_latest, 0)) AS heat_index
FROM latest l
JOIN prev p ON l.sector_code = p.sector_code
JOIN sector_narrative sn ON l.sector_code = sn.sector_code
ORDER BY l.market_cap_latest DESC
");
$stmt->execute(['latest' => $latest, 'prev' => $prev]);
$rotationRaw = $stmt->fetchAll(PDO::FETCH_ASSOC);

// Heat vs Flow 用データのみ Digital Gold / Stablecoins を除外
/*
$rotationForHeatFlow = array_filter($rotationRaw, function($r) {
    $code = strtolower(trim($r['sector_code']));
    return !in_array($code, ['digital_gold', 'stablecoins']);
});
*/
// バブルを統一したので除外なし
$rotationForHeatFlow = $rotationRaw;

// 整形（全体用）
$sectorNames = array_column($rotationRaw, 'sector_name');
$marketCaps  = array_map('floatval', array_column($rotationRaw, 'market_cap_latest'));
$changePcts  = array_map('floatval', array_column($rotationRaw, 'change_pct'));
$heats       = array_map('floatval', array_column($rotationRaw, 'heat_index'));

// 整形（Heat vs Flow用）
$sectorNamesHF = array_column($rotationForHeatFlow, 'sector_name');
$marketCapsHF  = array_map('floatval', array_column($rotationForHeatFlow, 'market_cap_latest'));
$changePctsHF  = array_map('floatval', array_column($rotationForHeatFlow, 'change_pct'));
$heatsHF       = array_map('floatval', array_column($rotationForHeatFlow, 'heat_index'));

// Heatカラー関数
function heatColor($v) {
    if ($v > 0.15) return "rgba(255, 80, 80, 0.8)";
    if ($v > 0.08) return "rgba(255, 200, 80, 0.8)";
    return "rgba(80, 200, 120, 0.8)";
}
$colors = array_map("heatColor", $heats);
$colorsHF = array_map("heatColor", $heatsHF);

// Dominance合計値（総時価総額）
$totalMarketCap = array_sum($marketCaps);
//$totalDisplay = number_format($totalMarketCap / 1_000_000_000, 0) . "B";
$totalDisplay = "合計の時価総額\n$" . number_format($totalMarketCap, 0);

// Trend用データ（30日分）
$inClause = implode(",", array_map(fn($d) => $pdo->quote($d), $dates));
$stmtTrend = $pdo->query("
SELECT snapshot_at, sn.sector_name, SUM(sd.market_cap) AS market_cap
FROM sector_data sd
JOIN sector_narrative sn ON sd.sector_code = sn.sector_code
WHERE snapshot_at IN ($inClause)
GROUP BY snapshot_at, sn.sector_name
ORDER BY snapshot_at ASC
");
$trendRaw = $stmtTrend->fetchAll(PDO::FETCH_ASSOC);

// Trend用データ整形
$trendData = [];
foreach ($trendRaw as $row) {
    $trendData[$row['sector_name']][$row['snapshot_at']] = (float)$row['market_cap'];
}

// 各スナップショットの総時価総額
$totalByDate = [];
foreach ($trendRaw as $row) {
    $totalByDate[$row['snapshot_at']] = ($totalByDate[$row['snapshot_at']] ?? 0) + (float)$row['market_cap'];
}

// 比率化
$trendRatios = [];
foreach ($trendData as $sector => $vals) {
    $trendRatios[$sector] = [];
    foreach ($dates as $d) {
        $trendRatios[$sector][] = isset($vals[$d]) && $totalByDate[$d] > 0
            ? $vals[$d] / $totalByDate[$d]
            : null;
    }
}

// Trend凡例をDominance順に並べ替え
$trendRatiosSorted = [];
foreach ($sectorNames as $name) {
    if (isset($trendRatios[$name])) {
        $trendRatiosSorted[$name] = $trendRatios[$name];
    }
}

// ★ BTC情報取得
$btcLatest = $pdo->query("SELECT market_cap FROM sector_data WHERE sector_code = 'digital_gold' AND snapshot_at = '$latest'")->fetchColumn();
$btcPrev   = $pdo->query("SELECT market_cap FROM sector_data WHERE sector_code = 'digital_gold' AND snapshot_at = '$prev'")->fetchColumn();
$btcChangeRate = (($btcLatest - $btcPrev) / $btcPrev) * 100;

// 相関係数を計算する関数（ピアソン相関）
// Dominance順のセクターリストを使用
$sectorList = $sectorNames;

// 相関係数を計算する関数（ピアソン相関）
function correlation($x, $y) {
    $n = count($x);
    if ($n < 2) return null;
    $meanX = array_sum($x) / $n;
    $meanY = array_sum($y) / $n;
    $num = 0; $denX = 0; $denY = 0;
    for ($i = 0; $i < $n; $i++) {
        if ($x[$i] === null || $y[$i] === null) continue;
        $dx = $x[$i] - $meanX;
        $dy = $y[$i] - $meanY;
        $num += $dx * $dy;
        $denX += $dx ** 2;
        $denY += $dy ** 2;
    }
    return ($denX && $denY) ? $num / sqrt($denX * $denY) : null;
}

// 相関行列を作成（Dominance順）
$correlationMatrix = [];
foreach ($sectorList as $i => $sectorA) {
    foreach ($sectorList as $j => $sectorB) {
        $x = array_values($trendData[$sectorA] ?? []);
        $y = array_values($trendData[$sectorB] ?? []);
        $corr = correlation($x, $y);
        $correlationMatrix[] = [
            'x' => $sectorA,
            'y' => $sectorB,
            'v' => round($corr, 3),
            'sectorA' => $sectorA,
            'sectorB' => $sectorB
        ];
    }
}

// 相関行列を2次元配列に整形
$correlationMatrixFormatted = [];
foreach ($sectorList as $i => $sectorA) {
    $correlationMatrixFormatted[$i] = [];
    foreach ($sectorList as $j => $sectorB) {
        $corr = null;
        foreach ($correlationMatrix as $item) {
            if ($item['sectorA'] === $sectorA && $item['sectorB'] === $sectorB) {
                $corr = $item['v'];
                break;
            }
        }
        $correlationMatrixFormatted[$i][$j] = $corr;
    }
}
?>

