  <script>
  const sectorNames = <?= json_encode($sectorNames) ?>;
  const marketCaps  = <?= json_encode($marketCaps) ?>;
  const changePcts  = <?= json_encode($changePcts) ?>;
  const heats       = <?= json_encode($heats) ?>;
  const colors      = <?= json_encode($colors) ?>;
  const totalDisplay = <?= json_encode($totalDisplay) ?>;

  const sectorNamesHF = <?= json_encode($sectorNamesHF) ?>;
  const marketCapsHF  = <?= json_encode($marketCapsHF) ?>;
  const changePctsHF  = <?= json_encode($changePctsHF) ?>;
  const heatsHF       = <?= json_encode($heatsHF) ?>;
  const colorsHF      = <?= json_encode($colorsHF) ?>;

  const trendLabels = <?= json_encode($dates) ?>;
  const trendRatios = <?= json_encode($trendRatiosSorted) ?>;
  const btcChangeRate = <?= json_encode($btcChangeRate) ?>;

  const sectorColors = [
      '#4e79a7','#f28e2b','#e15759','#76b7b2','#59a14f','#edc948',
      '#b07aa1','#ff9da7','#9c755f','#bab0ab',
      '#1f77b4','#ff7f0e','#2ca02c','#d62728','#9467bd','#8c564b',
      '#e377c2','#7f7f7f','#bcbd22','#17becf',
      '#393b79','#5254a3','#6b6ecf','#9c9ede','#637939','#8ca252',
      '#b5cf6b','#cedb9c','#8c6d31','#bd9e39','#e7ba52','#e7cb94',
      '#843c39','#ad494a','#d6616b','#e7969c','#7b4173','#a55194',
      '#ce6dbd','#de9ed6','#3182bd','#6baed6'
  ];

  // 中央テキスト表示プラグイン
  const centerTextPlugin = {
      id: 'centerText',
      afterDraw(chart) {
          if (!chart.$centerText) return;
          const { ctx, chartArea: { width, height } } = chart;
          ctx.save();
          ctx.font = 'bold 24px sans-serif';
          ctx.fillStyle = '#333';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';
          const lines = chart.$centerText.split('\n');
          const lineHeight = 26;
          const startY = height / 2 - (lineHeight * (lines.length - 1)) / 2;
          lines.forEach((line, i) => {
              ctx.fillText(line, width / 2, startY + i * lineHeight);
          });
          ctx.restore();
      }
  };

  // Dominance（ドーナツ）
  const dominanceChart = new Chart(document.getElementById('dominanceChart'), {
      type: 'doughnut',
      data: {
          labels: sectorNames,
          datasets: [{
              data: marketCaps,
              backgroundColor: sectorColors,
              borderWidth: 0
          }]
      },
      options: {
          cutout: '70%',
          plugins: {
              legend: {
                  position: 'right',
                  labels: {
                      boxWidth: 50,
                      boxHeight: 15, 
                      borderRadius: 3,
                      borderColor: 'transparent',
                      color: '#999',
                      padding: 12,
                      generateLabels: chart => {
                          const data = chart.data;
                          const meta = chart.getDatasetMeta(0);
                          return data.labels.map((label, i) => {
                              const hidden = meta.data[i].hidden;
                              return {
                                  text: label,
                                  fillStyle: data.datasets[0].backgroundColor[i],
                                  strokeStyle: 'transparent',
                                  hidden: hidden,
                                  font: {
                                      style: hidden ? 'line-through' : 'normal',
                                      color: hidden ? '#999' : '#777'
                                  },
                                  index: i
                              };
                          });
                      }
                  },
                  onClick: (e, legendItem, legend) => {
                      const chart = legend.chart;
                      const meta = chart.getDatasetMeta(0);
                      const idx = legendItem.index;
                      meta.data[idx].hidden = !meta.data[idx].hidden;
                      const visibleData = chart.data.datasets[0].data.filter((_, i) => !meta.data[i].hidden);
                      const totalVisible = visibleData.reduce((a, b) => a + b, 0);
                      chart.$centerText = `合計の時価総額\n$${totalVisible.toLocaleString()}`;
                      chart.update();
                  }
              },
              tooltip: {
                  enabled: true,
                  callbacks: {
                      title: () => '',
                      label: ctx => {
                          const label = ctx.label || '';
                          const value = ctx.parsed;
                          const total = ctx.chart.data.datasets[0].data.reduce((a, b) => a + b, 0);
                          const pct = ((value / total) * 100).toFixed(3);
                          return `${label}: $${value.toLocaleString()} (${pct}%)`;
                      }
                  }
              }
          }
      },
      plugins: [centerTextPlugin]
  });
  dominanceChart.$centerText = totalDisplay;
  dominanceChart.update();

  // Trend（Line）
  const trendChart = new Chart(document.getElementById('trendChart'), {
      type: 'line',
      data: {
          labels: trendLabels,
          datasets: Object.entries(trendRatios).map(([name, vals], i) => ({
              label: name,
              data: vals,
              borderColor: sectorColors[i % sectorColors.length],
              backgroundColor: sectorColors[i % sectorColors.length],
              fill: true,
              spanGaps: true
          }))
      },
      options: {
          plugins: {
              title: { display: false },
              tooltip: { enabled: false },
              legend: {
                  position: 'top',
                  onClick: (e, legendItem, legend) => {
                      const chart = legend.chart;
                      const index = legendItem.datasetIndex;
                      const meta = chart.getDatasetMeta(index);
                      meta.hidden = meta.hidden === null ? !chart.data.datasets[index].hidden : null;
                      const visibleDatasets = chart.data.datasets.filter((ds, i) => !chart.getDatasetMeta(i).hidden);
                      const summed = trendLabels.map((_, idx) =>
                          visibleDatasets.reduce((sum, ds) => sum + (ds.data[idx] || 0), 0)
                      );
                      const maxSum = Math.max(...summed);
                      chart.options.scales.y.max = maxSum;
                      let decimals = 0;
                      if (maxSum < 0.001) decimals = 3;
                      else if (maxSum < 0.01) decimals = 2;
                      else if (maxSum < 0.1) decimals = 1;
                      chart.options.scales.y.ticks.callback = value => (value * 100).toFixed(decimals) + '%';
                      chart.update();
                  }
              }
          },
          interaction: { mode: 'index', intersect: false },
          scales: {
              x: { 
                stacked: true,
                ticks: {
                  maxRotation: 90,
                  minRotation: 90
                }
              },
              y: {
                  stacked: true,
                  min: 0,
                  max: 1,
                  title: { display: true, text: '市場シェア (%)' },
                  ticks: { callback: value => (value * 100).toFixed(0) + '%' }
              }
          }
      }
  });

  // Heat vs Flow（Scatter）
  const scatterData = sectorNamesHF.map((name, i) => ({
      x: heatsHF[i],
      y: changePctsHF[i],
      r: 10,
      label: name
  }));
  new Chart(document.getElementById('heatFlowChart'), {
      type: 'bubble',
      data: {
          datasets: [{
              data: scatterData,
              backgroundColor: colorsHF
          }]
      },
      options: {
          layout: {
              padding: {
                  top: 50,
                  right: 10,
                  bottom: 10,
                  left: 10
              }
          },
          plugins: {
              title: { display: false },
              legend: { display: false },
              tooltip: {
                  callbacks: {
                      label: ctx => `${ctx.raw.label}: Heat=${ctx.raw.x.toFixed(2)}, Change=${ctx.raw.y.toFixed(1)}%`
                  }
              }
          },
          scales: {
              x: { 
                title: { 
                  display: true, 
                  text: '過熱度 (出来高/時価総額)' 
                }, 
                min: 0,
              },
              y: { title: { display: true, text: '前日からの資金移動比率 (%)' } }
          }
      }
  });

  // Rotation（Bar）
  new Chart(document.getElementById('rotationChart'), {
      type: 'bar',
      data: {
          labels: sectorNames,
          datasets: [{
              label: 'Market Cap Change (%)',
              data: changePcts,
              backgroundColor: colors,
          }]
      },
      options: {
          plugins: { title: { display: false }, legend: { display: false } },
          scales: { 
            x: { 
              stacked: true,
              ticks: {
                maxRotation: 90,
                minRotation: 90
              }
            },
            y: { title: { display: true, text: '前日からの資金移動比率 (%)' } } }
      }
  });
        
  // ★ BTC比較：過熱度と資金移動
  const btcMomentumData = sectorNames.map((name, i) => {
      const isBTC = name.toLowerCase().includes('digital gold');
      return {
          x: changePcts[i] - btcChangeRate,
          y: heats[i],
          r: 10,
          label: name,
          backgroundColor: isBTC ? 'rgba(80,80,80,0.6)' : colors[i]
      };
  });

  // X軸の範囲を計算（対称にするため）
  const xValues = btcMomentumData.map(d => d.x);
  const xMin = Math.min(...xValues);
  const xMax = Math.max(...xValues);
  const xRange = Math.max(Math.abs(xMin), Math.abs(xMax)) * 1.1;

  new Chart(document.getElementById('btcMomentumChart'), {
      type: 'bubble',
      data: {
          datasets: [{
              data: btcMomentumData,
              backgroundColor: btcMomentumData.map(d => d.backgroundColor)
          }]
      },
      options: {
          layout: {
              padding: {
                  top: 50,
                  right: 10,
                  bottom: 10,
                  left: 10
              }
          },
          scales: {
              x: { 
                  title: { display: true, text: 'BTC比較の資金移動比率 (セクターΔ - BTCΔ) %' },
                  min: -xRange,
                  max: xRange
              },
              y: { 
                  title: { display: true, text: '過熱度（出来高/時価総額）' },
                  min: 0,
                  max: 1.0
              }
          },
          plugins: {
              legend: { display: false },
              tooltip: {
                  callbacks: {
                      label: ctx => {
                          const mc = marketCaps[sectorNames.indexOf(ctx.raw.label)];
                          return [
                              `${ctx.raw.label}`,
                              `BTC比較: ${ctx.raw.x.toFixed(2)}%`,
                              `過熱度: ${ctx.raw.y.toFixed(3)}`,
                              `時価総額: $${mc.toLocaleString()}`
                          ];
                      }
                  }
              },
              annotation: {
                  annotations: {
                      // 右上（BTC超え＋高過熱）- 薄い赤
                      quadrant1: {
                          type: 'box',
                          xMin: 0,
                          xMax: xRange,
                          yMin: 0.15,
                          yMax: 1.0,
                          backgroundColor: 'rgba(255, 200, 200, 0.15)',
                          borderWidth: 0,
                          drawTime: 'beforeDatasetsDraw'
                      },
                      // 左上（BTC劣後＋高過熱）- 薄い黄
                      quadrant2: {
                          type: 'box',
                          xMin: -xRange,
                          xMax: 0,
                          yMin: 0.15,
                          yMax: 1.0,
                          backgroundColor: 'rgba(255, 255, 200, 0.15)',
                          borderWidth: 0,
                          drawTime: 'beforeDatasetsDraw'
                      },
                      // 右下（BTC超え＋静か）- 薄い緑
                      quadrant3: {
                          type: 'box',
                          xMin: 0,
                          xMax: xRange,
                          yMin: 0,
                          yMax: 0.15,
                          backgroundColor: 'rgba(200, 255, 200, 0.15)',
                          borderWidth: 0,
                          drawTime: 'beforeDatasetsDraw'
                      },
                      // 左下（BTC劣後＋静か）- 薄い灰色
                      quadrant4: {
                          type: 'box',
                          xMin: -xRange,
                          xMax: 0,
                          yMin: 0,
                          yMax: 0.15,
                          backgroundColor: 'rgba(220, 220, 220, 0.15)',
                          borderWidth: 0,
                          drawTime: 'beforeDatasetsDraw'
                      },
                      // X軸基準線
                      xLine: { 
                          type: 'line', 
                          xMin: 0, 
                          xMax: 0, 
                          borderColor: '#999', 
                          borderWidth: 1, 
                          borderDash: [4,4],
                          drawTime: 'afterDatasetsDraw'
                      },
                      // Y軸基準線
                      yLine: {
                          type: 'line',
                          yMin: 0.15,
                          yMax: 0.15,
                          borderColor: '#999',
                          borderWidth: 1,
                          borderDash: [4,4],
                          drawTime: 'afterDatasetsDraw'
                      }
                  }
              }
          }
      }
  });

  // 相関マトリクスをChart.jsで描画
  const correlationData = <?= json_encode($correlationMatrix) ?>;
  const sectorList = <?= json_encode($sectorList) ?>;

  // 相関値を2次元配列に変換
  const corrMatrix = [];
  for (let i = 0; i < sectorList.length; i++) {
      corrMatrix[i] = [];
      for (let j = 0; j < sectorList.length; j++) {
          const item = correlationData.find(d => d.sectorA === sectorList[i] && d.sectorB === sectorList[j]);
          corrMatrix[i][j] = item ? item.v : null;
      }
  }

  // ヒートカラー関数
  function getHeatColor(corr) {
      if (corr === null) return 'rgba(200, 200, 200, 0.3)';
      
      let r, g, b;
      if (corr >= 0) {
          const intensity = corr;
          r = 255;
          g = Math.round(255 * (1 - intensity));
          b = Math.round(255 * (1 - intensity));
      } else {
          const intensity = Math.abs(corr);
          r = Math.round(255 * (1 - intensity));
          g = Math.round(255 * (1 - intensity));
          b = 255;
      }
      return `rgba(${r}, ${g}, ${b}, 0.9)`;
  }

  // ダミーデータ（チャート用）
  const dummyData = sectorList.map((_, i) => i);

  const chart = new Chart(document.getElementById('correlationChart'), {
      type: 'scatter',
      data: {
          labels: sectorList,
          datasets: [{
              label: 'Correlation Matrix',
              data: dummyData.map(i => ({ x: 0, y: i })),
              pointRadius: 0,
              showLine: false
          }]
      },
      options: {
          responsive: true,
          maintainAspectRatio: false,
          layout: {
              padding: {
                  left: 5,  // Y軸ラベル用の余白
                  right: 30,  // 右端の余白を追加
                  bottom: 5,  // X軸ラベル用の余白を増やす
                  top: 20
              }
          },
          plugins: {
              legend: { display: false },
              tooltip: {
                  enabled: false
              }
          },
          scales: {
              x: {
                  type: 'category',
                  labels: sectorList,
                  offset: true,  // ラベルをセルの中央に配置
                  ticks: {
                      font: { size: 10 },
                      maxRotation: 90,
                      minRotation: 90,
                      padding: 0  // ラベルとマトリクスの間隔
                  },
                  grid: { 
                      display: false,
                      drawBorder: false
                  }
              },
              y: {
                  type: 'category',
                  labels: sectorList,
                  offset: true,  // ラベルをセルの中央に配置
                  ticks: {
                      font: { size: 10 }
                  },
                  grid: { 
                      display: false,
                      drawBorder: false
                  }
              }
          }
      },
      plugins: [{
          id: 'matrixPlugin',
          afterDatasetsDraw(chart) {
              const ctx = chart.ctx;
              const xScale = chart.scales.x;
              const yScale = chart.scales.y;
              
              // グリッドエリアの境界を取得
              const chartArea = chart.chartArea;
              
              // マトリクスセルを描画
              for (let i = 0; i < sectorList.length; i++) {
                  for (let j = 0; j < sectorList.length; j++) {
                      const corr = corrMatrix[i][j];
                      
                      // セルの座標（カテゴリスケール用）
                      const x = xScale.getPixelForValue(j);
                      const y = yScale.getPixelForValue(i);
                      
                      // セルのサイズを計算
                      const cellWidth = (chartArea.right - chartArea.left) / sectorList.length;
                      const cellHeight = (chartArea.bottom - chartArea.top) / sectorList.length;
                      
                      // セルの開始位置を調整（offset: trueの場合）
                      const cellX = chartArea.left + (j * cellWidth);
                      const cellY = chartArea.top + (i * cellHeight);
                      
                      // 背景色（同じセクターの場合は灰色）
                      if (i === j) {
                        ctx.fillStyle = 'rgba(100, 100, 100, 0.5)'; // 灰色
                      } else {
                        ctx.fillStyle = getHeatColor(corr);
                      }
                      ctx.fillRect(cellX, cellY, cellWidth, cellHeight);
                      
                      // 枠線
                      ctx.strokeStyle = '#999';
                      ctx.lineWidth = 0.5;
                      ctx.strokeRect(cellX, cellY, cellWidth, cellHeight);
                      
                      // 相関値を表示
                      if (corr !== null) {
                          const textColor = Math.abs(corr) > 0.5 ? '#ffffff' : '#000000';
                          ctx.fillStyle = textColor;
                          ctx.font = 'bold 10px Arial';
                          ctx.textAlign = 'center';
                          ctx.textBaseline = 'middle';
                          ctx.fillText(corr.toFixed(1), cellX + cellWidth / 2, cellY + cellHeight / 2);
                      }
                  }
              }
          }
      }]
  });

  // マウスホバーでツールチップ表示
  document.getElementById('correlationChart').addEventListener('mousemove', (e) => {
      const rect = e.target.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      
      const chartArea = chart.chartArea;
      
      // チャートエリア内かチェック
      if (x < chartArea.left || x > chartArea.right || y < chartArea.top || y > chartArea.bottom) {
          const tooltip = document.getElementById('customTooltip');
          if (tooltip) tooltip.style.display = 'none';
          return;
      }
      
      // セルのサイズ
      const cellWidth = (chartArea.right - chartArea.left) / sectorList.length;
      const cellHeight = (chartArea.bottom - chartArea.top) / sectorList.length;
      
      // インデックスを計算
      const j = Math.floor((x - chartArea.left) / cellWidth);
      const i = Math.floor((y - chartArea.top) / cellHeight);
      
      if (i >= 0 && i < sectorList.length && j >= 0 && j < sectorList.length) {
          const corr = corrMatrix[i][j];
          if (corr !== null) {
              // カスタムツールチップ表示
              const tooltip = document.getElementById('customTooltip') || createTooltip();
              tooltip.innerHTML = `
                  <strong>${sectorList[i]} ↔ ${sectorList[j]}</strong><br>
                  相関: ${corr.toFixed(3)}
              `;
              tooltip.style.display = 'block';
              tooltip.style.left = (e.clientX + 10) + 'px';
              tooltip.style.top = (e.clientY + 10) + 'px';
          }
      }
  });

  // マウスホバーでツールチップ表示
  document.getElementById('correlationChart').addEventListener('mousemove', (e) => {
      const rect = e.target.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      
      const chartArea = chart.chartArea;
      
      // チャートエリア内かチェック
      if (x < chartArea.left || x > chartArea.right || y < chartArea.top || y > chartArea.bottom) {
          const tooltip = document.getElementById('customTooltip');
          if (tooltip) tooltip.style.display = 'none';
          return;
      }
      
      // セルのサイズ
      const cellWidth = (chartArea.right - chartArea.left) / sectorList.length;
      const cellHeight = (chartArea.bottom - chartArea.top) / sectorList.length;
      
      // インデックスを計算
      const j = Math.floor((x - chartArea.left) / cellWidth);
      const i = Math.floor((y - chartArea.top) / cellHeight);
      
      if (i >= 0 && i < sectorList.length && j >= 0 && j < sectorList.length) {
          const corr = corrMatrix[i][j];
          if (corr !== null) {
              // カスタムツールチップ表示
              const tooltip = document.getElementById('customTooltip') || createTooltip();
              tooltip.innerHTML = `
                  <strong>${sectorList[i]} ↔ ${sectorList[j]}</strong><br>
                  相関: ${corr.toFixed(3)}
              `;
              tooltip.style.display = 'block';
              
              // ツールチップの位置を調整（画面外に出ないように）
              const tooltipRect = tooltip.getBoundingClientRect();
              let left = e.clientX + 10;
              let top = e.clientY - tooltipRect.height - 15; // 上に表示（矢印分を考慮）
              
              // 画面右端チェック
              if (left + tooltipRect.width > window.innerWidth) {
                  left = e.clientX - tooltipRect.width - 10;
              }
              
              // 画面上端チェック
              if (top < 0) {
                  top = e.clientY + 15; // 下に表示
                  tooltip.classList.remove('top');
              } else {
                  tooltip.classList.add('top');
              }
              
              tooltip.style.left = left + 'px';
              tooltip.style.top = top + 'px';
          }
      }
  });

  // マウスホバーでツールチップ表示
  document.getElementById('correlationChart').addEventListener('mousemove', (e) => {
      const rect = e.target.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      
      const chartArea = chart.chartArea;
      
      // チャートエリア内かチェック
      if (x < chartArea.left || x > chartArea.right || y < chartArea.top || y > chartArea.bottom) {
          const tooltip = document.getElementById('customTooltip');
          if (tooltip) tooltip.style.display = 'none';
          return;
      }
      
      // セルのサイズ
      const cellWidth = (chartArea.right - chartArea.left) / sectorList.length;
      const cellHeight = (chartArea.bottom - chartArea.top) / sectorList.length;
      
      // インデックスを計算
      const j = Math.floor((x - chartArea.left) / cellWidth);
      const i = Math.floor((y - chartArea.top) / cellHeight);
      
      if (i >= 0 && i < sectorList.length && j >= 0 && j < sectorList.length) {
          const corr = corrMatrix[i][j];
          if (corr !== null) {
              // カスタムツールチップ表示
              const tooltip = document.getElementById('customTooltip') || createTooltip();
              tooltip.innerHTML = `
                  <strong>${sectorList[i]} ↔ ${sectorList[j]}</strong><br>
                  相関: ${corr.toFixed(3)}
              `;
              tooltip.style.display = 'block';
              
              // 一旦表示してサイズを取得
              const tooltipRect = tooltip.getBoundingClientRect();
              
              // ツールチップを上に表示（デフォルト）
              let left = e.clientX - tooltipRect.width / 2;
              let top = e.clientY - tooltipRect.height - 15; // 15px = 矢印の高さ + 余白
              let arrowPosition = '50%'; // 中央
              let showBelow = false;
              
              // 画面上端チェック
              if (top < 0) {
                  top = e.clientY + 15; // 下に表示
                  showBelow = true;
              }
              
              // 画面左端チェック
              if (left < 0) {
                  arrowPosition = (e.clientX) + 'px';
                  left = 0;
              }
              
              // 画面右端チェック
              if (left + tooltipRect.width > window.innerWidth) {
                  const overflow = (left + tooltipRect.width) - window.innerWidth;
                  arrowPosition = (tooltipRect.width / 2 + overflow) + 'px';
                  left = window.innerWidth - tooltipRect.width;
              }
              
              // 位置とクラスを設定
              tooltip.style.left = left + 'px';
              tooltip.style.top = top + 'px';
              tooltip.style.setProperty('--arrow-left', arrowPosition);
              
              if (showBelow) {
                  tooltip.classList.remove('top');
                  tooltip.classList.add('bottom');
              } else {
                  tooltip.classList.remove('bottom');
                  tooltip.classList.add('top');
              }
          }
      }
  });

  document.getElementById('correlationChart').addEventListener('mouseleave', () => {
      const tooltip = document.getElementById('customTooltip');
      if (tooltip) tooltip.style.display = 'none';
  });

  // ツールチップ要素作成（Canvas風の吹き出し）
  function createTooltip() {
      // スタイルシートを追加（一度だけ）
      if (!document.getElementById('tooltipStyle')) {
          const style = document.createElement('style');
          style.id = 'tooltipStyle';
          style.textContent = `
              .canvas-tooltip {
                  --arrow-left: 50%;
              }
              
              .canvas-tooltip::after {
                  content: '';
                  position: absolute;
                  left: var(--arrow-left);
                  transform: translateX(-50%);
                  width: 0;
                  height: 0;
                  border-left: 6px solid transparent;
                  border-right: 6px solid transparent;
              }
              
              /* 上に表示（下向き矢印） */
              .canvas-tooltip.top::after {
                  bottom: -6px;
                  border-top: 6px solid rgba(0, 0, 0, 0.8);
                  border-bottom: none;
              }
              
              /* 下に表示（上向き矢印） */
              .canvas-tooltip.bottom::after {
                  top: -6px;
                  border-top: none;
                  border-bottom: 6px solid rgba(0, 0, 0, 0.8);
              }
          `;
          document.head.appendChild(style);
      }
      
      const tooltip = document.createElement('div');
      tooltip.id = 'customTooltip';
      tooltip.className = 'canvas-tooltip top';
      tooltip.style.cssText = `
          position: fixed;
          background-color: rgba(0, 0, 0, 0.8);
          color: #fff;
          padding: 10px 15px;
          border-radius: 6px;
          font-size: 12px;
          font-weight: normal;
          pointer-events: none;
          display: none;
          z-index: 1000;
          white-space: nowrap;
          box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
      `;
      document.body.appendChild(tooltip);
      return tooltip;
  }
  </script>
</body>
</html>